1	/**
2	 * The visualization controller will works as a state machine.
3	 * See files under the `doc` folder for transition descriptions.
4	 * See https://github.com/jakesgordon/javascript-state-machine
5	 * for the document of the StateMachine module.
6	 */
7	var Controller = StateMachine.create({
8	    initial: 'none',
9	    events: [
10	        {
11	            name: 'init',
12	            from: 'none',
13	            to:   'ready'
14	        },
15	        {
16	            name: 'search',
17	            from: 'starting',
18	            to:   'searching'
19	        },
20	        {
21	            name: 'pause',
22	            from: 'searching',
23	            to:   'paused'
24	        },
25	        {
26	            name: 'finish',
27	            from: 'searching',
28	            to:   'finished'
29	        },
30	        {
31	            name: 'resume',
32	            from: 'paused',
33	            to:   'searching'
34	        },
35	        {
36	            name: 'cancel',
37	            from: 'paused',
38	            to:   'ready'
39	        },
40	        {
41	            name: 'modify',
42	            from: 'finished',
43	            to:   'modified'
44	        },
45	        {
46	            name: 'reset',
47	            from: '*',
48	            to:   'ready'
49	        },
50	        {
51	            name: 'clear',
52	            from: ['finished', 'modified'],
53	            to:   'ready'
54	        },
55	        {
56	            name: 'start',
57	            from: ['ready', 'modified', 'restarting'],
58	            to:   'starting'
59	        },
60	        {
61	            name: 'restart',
62	            from: ['searching', 'finished'],
63	            to:   'restarting'
64	        },
65	        {
66	            name: 'dragStart',
67	            from: ['ready', 'finished'],
68	            to:   'draggingStart'
69	        },
70	        {
71	            name: 'dragEnd',
72	            from: ['ready', 'finished'],
73	            to:   'draggingEnd'
74	        },
75	        {
76	            name: 'drawWall',
77	            from: ['ready', 'finished'],
78	            to:   'drawingWall'
79	        },
80	        {
81	            name: 'eraseWall',
82	            from: ['ready', 'finished'],
83	            to:   'erasingWall'
84	        },
85	        {
86	            name: 'rest',
87	            from: ['draggingStart', 'draggingEnd', 'drawingWall', 'erasingWall'],
88	            to  : 'ready'
89	        },
90	    ],
91	});
92	
93	$.extend(Controller, {
94	    gridSize: [64, 36], // number of nodes horizontally and vertically
95	    operationsPerSecond: 300,
96	
97	    /**
98	     * Asynchronous transition from `none` state to `ready` state.
99	     */
100	    onleavenone: function() {
101	        var numCols = this.gridSize[0],
102	            numRows = this.gridSize[1];
103	
104	        this.grid = new PF.Grid(numCols, numRows);
105	
106	        View.init({
107	            numCols: numCols,
108	            numRows: numRows
109	        });
110	        View.generateGrid(function() {
111	            Controller.setDefaultStartEndPos();
112	            Controller.bindEvents();
113	            Controller.transition(); // transit to the next state (ready)
114	        });
115	
116	        this.$buttons = $('.control_button');
117	
118	        this.hookPathFinding();
119	
120	        return StateMachine.ASYNC;
121	        // => ready
122	    },
123	    ondrawWall: function(event, from, to, gridX, gridY) {
124	        this.setWalkableAt(gridX, gridY, false);
125	        // => drawingWall
126	    },
127	    oneraseWall: function(event, from, to, gridX, gridY) {
128	        this.setWalkableAt(gridX, gridY, true);
129	        // => erasingWall
130	    },
131	    onsearch: function(event, from, to) {
132	        var grid,
133	            timeStart, timeEnd,
134	            finder = Panel.getFinder();
135	
136	        timeStart = window.performance ? performance.now() : Date.now();
137	        grid = this.grid.clone();
138	        this.path = finder.findPath(
139	            this.startX, this.startY, this.endX, this.endY, grid
140	        );
141	        this.operationCount = this.operations.length;
142	        timeEnd = window.performance ? performance.now() : Date.now();
143	        this.timeSpent = (timeEnd - timeStart).toFixed(4);
144	
145	        this.loop();
146	        // => searching
147	    },
148	    onrestart: function() {
149	        // When clearing the colorized nodes, there may be
150	        // nodes still animating, which is an asynchronous procedure.
151	        // Therefore, we have to defer the `abort` routine to make sure
152	        // that all the animations are done by the time we clear the colors.
153	        // The same reason applies for the `onreset` event handler.
154	        setTimeout(function() {
155	            Controller.clearOperations();
156	            Controller.clearFootprints();
157	            Controller.start();
158	        }, View.nodeColorizeEffect.duration * 1.2);
159	        // => restarting
160	    },
161	    onpause: function(event, from, to) {
162	        // => paused
163	    },
164	    onresume: function(event, from, to) {
165	        this.loop();
166	        // => searching
167	    },
168	    oncancel: function(event, from, to) {
169	        this.clearOperations();
170	        this.clearFootprints();
171	        // => ready
172	    },
173	    onfinish: function(event, from, to) {
174	        View.showStats({
175	            pathLength: PF.Util.pathLength(this.path),
176	            timeSpent:  this.timeSpent,
177	            operationCount: this.operationCount,
178	        });
179	        View.drawPath(this.path);
180	        // => finished
181	    },
182	    onclear: function(event, from, to) {
183	        this.clearOperations();
184	        this.clearFootprints();
185	        // => ready
186	    },
187	    onmodify: function(event, from, to) {
188	        // => modified
189	    },
190	    onreset: function(event, from, to) {
191	        setTimeout(function() {
192	            Controller.clearOperations();
193	            Controller.clearAll();
194	            Controller.buildNewGrid();
195	        }, View.nodeColorizeEffect.duration * 1.2);
196	        // => ready
197	    },
198	
199	    /**
200	     * The following functions are called on entering states.
201	     */
202	
203	    onready: function() {
204	        console.log('=> ready');
205	        this.setButtonStates({
206	            id: 1,
207	            text: 'Start Search',
208	            enabled: true,
209	            callback: $.proxy(this.start, this),
210	        }, {
211	            id: 2,
212	            text: 'Pause Search',
213	            enabled: false,
214	        }, {
215	            id: 3,
216	            text: 'Clear Walls',
217	            enabled: true,
218	            callback: $.proxy(this.reset, this),
219	        });
220	        // => [starting, draggingStart, draggingEnd, drawingStart, drawingEnd]
221	    },
222	    onstarting: function(event, from, to) {
223	        console.log('=> starting');
224	        // Clears any existing search progress
225	        this.clearFootprints();
226	        this.setButtonStates({
227	            id: 2,
228	            enabled: true,
229	        });
230	        this.search();
231	        // => searching
232	    },
233	    onsearching: function() {
234	        console.log('=> searching');
235	        this.setButtonStates({
236	            id: 1,
237	            text: 'Restart Search',
238	            enabled: true,
239	            callback: $.proxy(this.restart, this),
240	        }, {
241	            id: 2,
242	            text: 'Pause Search',
243	            enabled: true,
244	            callback: $.proxy(this.pause, this),
245	        });
246	        // => [paused, finished]
247	    },
248	    onpaused: function() {
249	        console.log('=> paused');
250	        this.setButtonStates({
251	            id: 1,
252	            text: 'Resume Search',
253	            enabled: true,
254	            callback: $.proxy(this.resume, this),
255	        }, {
256	            id: 2,
257	            text: 'Cancel Search',
258	            enabled: true,
259	            callback: $.proxy(this.cancel, this),
260	        });
261	        // => [searching, ready]
262	    },
263	    onfinished: function() {
264	        console.log('=> finished');
265	        this.setButtonStates({
266	            id: 1,
267	            text: 'Restart Search',
268	            enabled: true,
269	            callback: $.proxy(this.restart, this),
270	        }, {
271	            id: 2,
272	            text: 'Clear Path',
273	            enabled: true,
274	            callback: $.proxy(this.clear, this),
275	        });
276	    },
277	    onmodified: function() {
278	        console.log('=> modified');
279	        this.setButtonStates({
280	            id: 1,
281	            text: 'Start Search',
282	            enabled: true,
283	            callback: $.proxy(this.start, this),
284	        }, {
285	            id: 2,
286	            text: 'Clear Path',
287	            enabled: true,
288	            callback: $.proxy(this.clear, this),
289	        });
290	    },
291	
292	    /**
293	     * Define setters and getters of PF.Node, then we can get the operations
294	     * of the pathfinding.
295	     */
296	    hookPathFinding: function() {
297	
298	        PF.Node.prototype = {
299	            get opened() {
300	                return this._opened;
301	            },
302	            set opened(v) {
303	                this._opened = v;
304	                Controller.operations.push({
305	                    x: this.x,
306	                    y: this.y,
307	                    attr: 'opened',
308	                    value: v
309	                });
310	            },
311	            get closed() {
312	                return this._closed;
313	            },
314	            set closed(v) {
315	                this._closed = v;
316	                Controller.operations.push({
317	                    x: this.x,
318	                    y: this.y,
319	                    attr: 'closed',
320	                    value: v
321	                });
322	            },
323	            get tested() {
324	                return this._tested;
325	            },
326	            set tested(v) {
327	                this._tested = v;
328	                Controller.operations.push({
329	                    x: this.x,
330	                    y: this.y,
331	                    attr: 'tested',
332	                    value: v
333	                });
334	            },
335	        };
336	
337	        this.operations = [];
338	    },
339	    bindEvents: function() {
340	        $('#draw_area').mousedown($.proxy(this.mousedown, this));
341	        $(window)
342	            .mousemove($.proxy(this.mousemove, this))
343	            .mouseup($.proxy(this.mouseup, this));
344	    },
345	    loop: function() {
346	        var interval = 1000 / this.operationsPerSecond;
347	        (function loop() {
348	            if (!Controller.is('searching')) {
349	                return;
350	            }
351	            Controller.step();
352	            setTimeout(loop, interval);
353	        })();
