1	/**
2	 * The pathfinding visualization.
3	 * It uses raphael.js to show the grids.
4	 */
5	var View = {
6	    nodeSize: 30, // width and height of a single node, in pixel
7	    nodeStyle: {
8	        normal: {
9	            fill: 'white',
10	            'stroke-opacity': 0.2, // the border
11	        },
12	        blocked: {
13	            fill: 'grey',
14	            'stroke-opacity': 0.2,
15	        },
16	        start: {
17	            fill: '#0d0',
18	            'stroke-opacity': 0.2,
19	        },
20	        end: {
21	            fill: '#e40',
22	            'stroke-opacity': 0.2,
23	        },
24	        opened: {
25	            fill: '#98fb98',
26	            'stroke-opacity': 0.2,
27	        },
28	        closed: {
29	            fill: '#afeeee',
30	            'stroke-opacity': 0.2,
31	        },
32	        failed: {
33	            fill: '#ff8888',
34	            'stroke-opacity': 0.2,
35	        },
36	        tested: {
37	            fill: '#e5e5e5',
38	            'stroke-opacity': 0.2,
39	        },
40	    },
41	    nodeColorizeEffect: {
42	        duration: 50,
43	    },
44	    nodeZoomEffect: {
45	        duration: 200,
46	        transform: 's1.2', // scale by 1.2x
47	        transformBack: 's1.0',
48	    },
49	    pathStyle: {
50	        stroke: 'yellow',
51	        'stroke-width': 3,
52	    },
53	    supportedOperations: ['opened', 'closed', 'tested'],
54	    init: function(opts) {
55	        this.numCols      = opts.numCols;
56	        this.numRows      = opts.numRows;
57	        this.paper        = Raphael('draw_area');
58	        this.$stats       = $('#stats');
59	    },
60	    /**
61	     * Generate the grid asynchronously.
62	     * This method will be a very expensive task.
63	     * Therefore, in order to not to block the rendering of browser ui,
64	     * I decomposed the task into smaller ones. Each will only generate a row.
65	     */
66	    generateGrid: function(callback) {
67	        var i, j, x, y,
68	            rect,
69	            normalStyle, nodeSize,
70	            createRowTask, sleep, tasks,
71	            nodeSize    = this.nodeSize,
72	            normalStyle = this.nodeStyle.normal,
73	            numCols     = this.numCols,
74	            numRows     = this.numRows,
75	            paper       = this.paper,
76	            rects       = this.rects = [],
77	            $stats      = this.$stats;
78	
79	        paper.setSize(numCols * nodeSize, numRows * nodeSize);
80	
81	        createRowTask = function(rowId) {
82	            return function(done) {
83	                rects[rowId] = [];
84	                for (j = 0; j < numCols; ++j) {
85	                    x = j * nodeSize;
86	                    y = rowId * nodeSize;
87	
88	                    rect = paper.rect(x, y, nodeSize, nodeSize);
89	                    rect.attr(normalStyle);
90	                    rects[rowId].push(rect);
91	                }
92	                $stats.text(
93	                    'generating grid ' +
94	                    Math.round((rowId + 1) / numRows * 100) + '%'
95	                );
96	                done(null);
97	            };
98	        };
99	
100	        sleep = function(done) {
101	            setTimeout(function() {
102	                done(null);
103	            }, 0);
104	        };
105	
106	        tasks = [];
107	        for (i = 0; i < numRows; ++i) {
108	            tasks.push(createRowTask(i));
109	            tasks.push(sleep);
110	        }
111	
112	        async.series(tasks, function() {
113	            if (callback) {
114	                callback();
115	            }
116	        });
117	    },
118	    setStartPos: function(gridX, gridY) {
119	        var coord = this.toPageCoordinate(gridX, gridY);
120	        if (!this.startNode) {
121	            this.startNode = this.paper.rect(
122	                coord[0],
123	                coord[1],
124	                this.nodeSize,
125	                this.nodeSize
126	            ).attr(this.nodeStyle.normal)
127	             .animate(this.nodeStyle.start, 1000);
128	        } else {
129	            this.startNode.attr({ x: coord[0], y: coord[1] }).toFront();
130	        }
131	    },
132	    setEndPos: function(gridX, gridY) {
133	        var coord = this.toPageCoordinate(gridX, gridY);
134	        if (!this.endNode) {
135	            this.endNode = this.paper.rect(
136	                coord[0],
137	                coord[1],
138	                this.nodeSize,
139	                this.nodeSize
140	            ).attr(this.nodeStyle.normal)
141	             .animate(this.nodeStyle.end, 1000);
142	        } else {
143	            this.endNode.attr({ x: coord[0], y: coord[1] }).toFront();
144	        }
145	    },
146	    /**
147	     * Set the attribute of the node at the given coordinate.
148	     */
149	    setAttributeAt: function(gridX, gridY, attr, value) {
150	        var color, nodeStyle = this.nodeStyle;
151	        switch (attr) {
152	        case 'walkable':
