33	 */
34	function IDAStarFinder(opt) {
35	    opt = opt || {};
36	    this.allowDiagonal = opt.allowDiagonal;
37	    this.dontCrossCorners = opt.dontCrossCorners;
38	    this.diagonalMovement = opt.diagonalMovement;
39	    this.heuristic = opt.heuristic || Heuristic.manhattan;
40	    this.weight = opt.weight || 1;
41	    this.trackRecursion = opt.trackRecursion || false;
42	    this.timeLimit = opt.timeLimit || Infinity; // Default: no time limit.
43	
44	    if (!this.diagonalMovement) {
45	        if (!this.allowDiagonal) {
46	            this.diagonalMovement = DiagonalMovement.Never;
47	        } else {
48	            if (this.dontCrossCorners) {
49	                this.diagonalMovement = DiagonalMovement.OnlyWhenNoObstacles;
50	            } else {
51	                this.diagonalMovement = DiagonalMovement.IfAtMostOneObstacle;
52	            }
53	        }
54	    }
55	
56	    // When diagonal movement is allowed the manhattan heuristic is not
57	    // admissible, it should be octile instead
58	    if (this.diagonalMovement === DiagonalMovement.Never) {
